"use client";

import * as React from "react";
import { StickToBottom, useStickToBottomContext } from "use-stick-to-bottom";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface ConversationProps extends React.ComponentProps<"div"> {
  /** Behavior when content resizes. "smooth" animates, "instant" jumps. */
  resize?: "smooth" | "instant";
  /** Behavior on initial mount */
  initial?: "smooth" | "instant";
}

interface ConversationContentProps extends React.ComponentProps<"div"> {}

interface ConversationScrollAnchorProps extends React.ComponentProps<"div"> {
  /** Text to show when not at bottom */
  label?: string;
}

// =============================================================================
// COMPONENTS
// =============================================================================

function ConversationRoot({
  resize = "smooth",
  initial = "instant",
  className,
  children,
  ...props
}: ConversationProps) {
  return (
    <StickToBottom
      resize={resize}
      initial={initial}
      className={cn("relative flex flex-col h-full overflow-hidden", className)}
      {...props}
    >
      {children}
    </StickToBottom>
  );
}

function ConversationContent({
  className,
  children,
  ...props
}: ConversationContentProps) {
  return (
    <StickToBottom.Content
      className={cn("flex flex-col gap-4 p-4", className)}
      {...props}
    >
      {children}
    </StickToBottom.Content>
  );
}

function ConversationScrollAnchor({
  label = "Scroll to bottom",
  className,
  ...props
}: ConversationScrollAnchorProps) {
  const { isAtBottom, scrollToBottom } = useStickToBottomContext();

  if (isAtBottom) return null;

  return (
    <div
      data-slot="conversation-scroll-anchor"
      className={cn(
        "absolute bottom-4 left-1/2 -translate-x-1/2 z-10",
        className
      )}
      {...props}
    >
      <button
        type="button"
        onClick={() => scrollToBottom()}
        className={cn(
          "flex items-center gap-1.5 px-3 py-1.5 rounded-full",
          "bg-background/90 backdrop-blur-sm border border-border",
          "text-xs text-muted-foreground",
          "shadow-md hover:shadow-lg transition-shadow",
          "hover:text-foreground"
        )}
      >
        <svg
          width="12"
          height="12"
          viewBox="0 0 12 12"
          fill="none"
          className="shrink-0"
        >
          <path
            d="M6 2.5v7M3 7l3 3 3-3"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
        {label}
      </button>
    </div>
  );
}

// =============================================================================
// COMPOUND COMPONENT
// =============================================================================

ConversationRoot.displayName = "Conversation";
ConversationContent.displayName = "Conversation.Content";
ConversationScrollAnchor.displayName = "Conversation.ScrollAnchor";

const Conversation = Object.assign(ConversationRoot, {
  Content: ConversationContent,
  ScrollAnchor: ConversationScrollAnchor,
});

export { Conversation, useStickToBottomContext };
export type {
  ConversationProps,
  ConversationContentProps,
  ConversationScrollAnchorProps,
};
